import Matter from "../_snowpack/pkg/matter-js.js";

const docW = window.innerWidth;
const docH = window.innerHeight - 4;
const scale = Math.min(docW / 1200, docH / 1200, 1);
const debug = false;

const engine = Matter.Engine.create({
  gravity: { x: 0, y: 0 },
  positionIterations: 12,
});

export const render = Matter.Render.create({
  element: document.body,
  engine: engine,
  options: {
    width: docW,
    height: docH,
    wireframes: debug,
  },
});

const Bodies = Matter.Bodies;

const borders = [
  Bodies.rectangle(0, 0, 2, docH * 2, { isStatic: true }),
  Bodies.rectangle(docW, 0, 2, docH * 2, { isStatic: true }),
  Bodies.rectangle(0, 0, docW * 2, 2, { isStatic: true }),
  Bodies.rectangle(0, docH, docW * 2, 2, { isStatic: true }),
];

const midX = 500 * scale;
const midY = 500 * scale;

const bug = Bodies.rectangle(midX, midY, 300, 136, {
  render: { sprite: { texture: "beetle.png" } },
});

const constraints = [
  Matter.MouseConstraint.create(engine, {
    constraint: { render: { visible: debug }, stiffness: 0.5, damping: 0.1 },
  }),
];
const enemies = [];

const n = 10;
const initDist = 200;
const r = 300 * scale;
const chainOpts = {
  length: (2 * Math.PI * r) / n,
  stiffness: 0.5,
  damping: 0.2,
  render: { visible: debug },
};

let previous = null;
for (let i = 0; i < n; i++) {
  const angle = (i * 2 * Math.PI) / n;
  const b = Bodies.circle(
    initDist * Math.sin(angle) + midX,
    initDist * Math.cos(angle) + midY,
    80,
    { render: { fillStyle: "#" + Math.round(Math.random()*10+1).toString(16).repeat(3) }, velocity: {x: 100} },
  );
  enemies.push(b);
  constraints.push(
    Matter.Constraint.create({
      bodyA: bug,
      bodyB: b,
      length: r,
      stiffness: 0.01,
      damping: 0.005,
      render: {
        visible: debug,
      },
    }),
  );
  if (previous !== null) {
    constraints.push(
      Matter.Constraint.create({ bodyA: previous, bodyB: b, ...chainOpts }),
    );
  }
  previous = b;
}
constraints.push(
  Matter.Constraint.create({
    bodyA: previous,
    bodyB: enemies[0],
    ...chainOpts,
  }),
);

Matter.Composite.add(engine.world, [...enemies, bug, ...constraints]);

Matter.Render.run(render);

Matter.Composite.scale(engine.world, scale, scale, { x: midX, y: midY });
bug.render.sprite.yScale = bug.render.sprite.xScale = scale;
Matter.Composite.add(engine.world, borders);
setTimeout(() => Matter.Body.applyForce(bug, {x: midX-10*scale, y:midY}, {x: Math.random()*scale*5, y:0}), 1000);

const runner = Matter.Runner.create();
Matter.Runner.run(runner, engine);
